// Calculate previous month and 2-months-ago date ranges
const now = new Date();
const reportDate = now.toISOString().split('T')[0];

// Previous month
const prevMonthEnd = new Date(now.getFullYear(), now.getMonth(), 0); // last day of prev month
const prevMonthStart = new Date(now.getFullYear(), now.getMonth() - 1, 1);

// Two months ago
const twoMonthsAgoEnd = new Date(now.getFullYear(), now.getMonth() - 1, 0); // last day of 2 months ago
const twoMonthsAgoStart = new Date(now.getFullYear(), now.getMonth() - 2, 1);

const fmt = (d) => d.toISOString().split('T')[0];

const prevMonthLabel = prevMonthStart.toLocaleString('en-US', { month: 'long', year: 'numeric' });
const twoMonthsAgoLabel = twoMonthsAgoStart.toLocaleString('en-US', { month: 'long', year: 'numeric' });

return [{ json: {
  reportDate,
  prevMonthStart: fmt(prevMonthStart),
  prevMonthEnd: fmt(prevMonthEnd),
  twoMonthsAgoStart: fmt(twoMonthsAgoStart),
  twoMonthsAgoEnd: fmt(twoMonthsAgoEnd),
  prevMonthLabel,
  twoMonthsAgoLabel,
  nowIso: now.toISOString()
} }];

// Compare previous month vs 2 months ago across all KPIs
const dates = $('Calculate Month Ranges').first().json;
const prevMonthRaw = $('Fetch Previous Month Metrics').first().json;
const twoMonthsRaw = $('Fetch Two Months Ago Metrics').first().json;

const prevMonth = prevMonthRaw.body || prevMonthRaw || [];
const twoMonths = twoMonthsRaw.body || twoMonthsRaw || [];

// Compute monthly averages per metric
function monthlyAverages(metrics) {
  const byName = {};
  const arr = Array.isArray(metrics) ? metrics : [];
  for (const m of arr) {
    if (!byName[m.metric_name]) byName[m.metric_name] = [];
    byName[m.metric_name].push(parseFloat(m.metric_value) || 0);
  }
  const result = {};
  for (const [name, vals] of Object.entries(byName)) {
    result[name] = {
      avg: vals.reduce((s, v) => s + v, 0) / vals.length,
      sum: vals.reduce((s, v) => s + v, 0),
      count: vals.length,
      min: Math.min(...vals),
      max: Math.max(...vals)
    };
  }
  return result;
}

const prevAvgs = monthlyAverages(prevMonth);
const twoAvgs = monthlyAverages(twoMonths);

// Calculate MoM change for each metric
const allMetricNames = [...new Set([...Object.keys(prevAvgs), ...Object.keys(twoAvgs)])];
const changes = [];
for (const name of allMetricNames) {
  const curr = prevAvgs[name] || { avg: 0, sum: 0, count: 0 };
  const prev = twoAvgs[name] || { avg: 0, sum: 0, count: 0 };
  const changePct = prev.avg !== 0
    ? ((curr.avg - prev.avg) / Math.abs(prev.avg)) * 100
    : (curr.avg > 0 ? 100 : 0);
  changes.push({
    metric: name,
    currentAvg: Math.round(curr.avg * 100) / 100,
    previousAvg: Math.round(prev.avg * 100) / 100,
    changePct: Math.round(changePct * 10) / 10,
    absChange: Math.abs(changePct),
    direction: changePct >= 0 ? 'up' : 'down',
    currentSum: Math.round(curr.sum * 100) / 100,
    dataPoints: curr.count
  });
}

// Sort by absolute change
changes.sort((a, b) => b.absChange - a.absChange);

// Top 3 up and top 3 down
const topUp = changes.filter(c => c.direction === 'up').slice(0, 3);
const topDown = changes.filter(c => c.direction === 'down').slice(0, 3);

// Format helpers
const fmt = (n) => {
  if (n === undefined || n === null) return '\u2014';
  return Number(n).toLocaleString('en-US', { maximumFractionDigits: 2 });
};
const sign = (v) => v >= 0 ? '+' : '';

// Build highlights
const highlights = [];
if (topUp.length > 0) {
  for (const m of topUp) {
    highlights.push(`${m.metric.replace(/_/g, ' ')}: +${m.changePct}% (${fmt(m.previousAvg)} -> ${fmt(m.currentAvg)})`);
  }
}
if (topDown.length > 0) {
  for (const m of topDown) {
    highlights.push(`${m.metric.replace(/_/g, ' ')}: ${m.changePct}% (${fmt(m.previousAvg)} -> ${fmt(m.currentAvg)})`);
  }
}
if (highlights.length === 0) {
  highlights.push('Monthly trend analysis active \u2014 collecting baseline data across KPIs');
}

// Build table rows for all metrics
const tableHeaders = ['Metric', dates.prevMonthLabel + ' Avg', dates.twoMonthsAgoLabel + ' Avg', 'MoM Change'];
const tableRows = changes.map(c => [
  c.metric.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase()),
  fmt(c.currentAvg),
  fmt(c.previousAvg),
  sign(c.changePct) + c.changePct + '%'
]);

// Top metrics cards
const topMetrics = [
  { label: 'KPIs Tracked', value: allMetricNames.length.toString(), change: '' },
  { label: 'Biggest Gainer', value: topUp.length > 0 ? topUp[0].metric.replace(/_/g, ' ') : '\u2014', change: topUp.length > 0 ? '+' + topUp[0].changePct + '%' : '' },
  { label: 'Biggest Decliner', value: topDown.length > 0 ? topDown[0].metric.replace(/_/g, ' ') : '\u2014', change: topDown.length > 0 ? topDown[0].changePct + '%' : '' },
  { label: 'Data Points', value: fmt(Array.isArray(prevMonth) ? prevMonth.length : 0), change: '' }
];

// Actions
const actions = [];
if (topDown.length > 0 && topDown[0].absChange > 20) {
  actions.push('Investigate ' + topDown[0].metric.replace(/_/g, ' ') + ' decline of ' + topDown[0].changePct + '% \u2014 check for operational or seasonal cause');
}
if (topUp.length > 0 && topUp[0].absChange > 30) {
  actions.push('Capitalize on ' + topUp[0].metric.replace(/_/g, ' ') + ' surge \u2014 double down on what drove +' + topUp[0].changePct + '%');
}
if (changes.length > 0) {
  const stableCount = changes.filter(c => c.absChange < 5).length;
  if (stableCount > changes.length * 0.7) {
    actions.push('Most KPIs stable month-over-month \u2014 consider new experiments to drive growth');
  }
}
if (actions.length === 0) {
  actions.push('Review trend data and identify optimization opportunities for the coming month');
}

// Build sections for TG-118
const sections = [
  { type: 'metrics', title: 'Monthly Overview', items: topMetrics },
  { type: 'highlights', title: 'Biggest Movers', items: highlights }
];

if (tableRows.length > 0) {
  sections.push({ type: 'table', title: 'All KPI Trends', headers: tableHeaders, rows: tableRows });
}

sections.push({ type: 'actions', title: 'Recommended Actions', items: actions });

return [{ json: {
  report_title: 'Monthly Trend Analysis',
  report_subtitle: dates.prevMonthLabel + ' vs ' + dates.twoMonthsAgoLabel + ' | TotalGuard Intelligence',
  sections,
  storePayload: {
    report_type: 'monthly_trend',
    report_date: dates.reportDate,
    report_data: {
      prev_month: dates.prevMonthLabel,
      comparison_month: dates.twoMonthsAgoLabel,
      kpis_tracked: allMetricNames.length,
      top_gainers: topUp,
      top_decliners: topDown,
      all_changes: changes,
      data_points_prev: Array.isArray(prevMonth) ? prevMonth.length : 0,
      data_points_two: Array.isArray(twoMonths) ? twoMonths.length : 0
    },
    generated_by: 'TG-119'
  }
} }];
